// ─── Supabase Client ──────────────────────────────────────────
// Install: npm i @supabase/supabase-js  OR  use CDN in index.html
// For Vite/CRA: import from "@supabase/supabase-js"
// Replace these env vars with your actual Supabase project values
// Lightweight Supabase REST helper (no SDK dependency for JSX preview)
const supa = {
  url: SUPABASE_URL,
  key: SUPABASE_ANON,
  _token: null,

  // Auth header
  _headers(extra = {}) {
    return {
      "Content-Type": "application/json",
      "apikey": this.key,
      "Authorization": `Bearer ${this._token ?? this.key}`,
      ...extra,
    };
  },

  // ── Auth ───────────────────────────────────────────────────
  auth: {
    _parent: null,
    async signUp({ email, password, options }) {
      const res = await fetch(`${supa.url}/auth/v1/signup`, {
        method: "POST",
        headers: supa._headers(),
        body: JSON.stringify({ email, password, data: options?.data ?? {} }),
      });
      const data = await res.json();
      if (data.access_token) supa._token = data.access_token;
      return { data, error: res.ok ? null : data };
    },
    async signInWithPassword({ email, password }) {
      const res = await fetch(`${supa.url}/auth/v1/token?grant_type=password`, {
        method: "POST",
        headers: supa._headers(),
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (data.access_token) supa._token = data.access_token;
      return { data: { user: data.user, session: data }, error: res.ok ? null : data };
    },
    async signOut() {
      await fetch(`${supa.url}/auth/v1/logout`, {
        method: "POST", headers: supa._headers(),
      });
      supa._token = null;
      try { localStorage.removeItem("sb_session"); } catch(_) {}
      return { error: null };
    },
    async getSession() {
      try {
        const saved = localStorage.getItem("sb_session");
        if (saved) {
          const session = JSON.parse(saved);
          supa._token = session.access_token;
          return { data: { session }, error: null };
        }
      } catch(_) {}
      return { data: { session: null }, error: null };
    },
    async resetPasswordForEmail(email) {
      const res = await fetch(`${supa.url}/auth/v1/recover`, {
        method: "POST", headers: supa._headers(),
        body: JSON.stringify({ email }),
      });
      return { error: res.ok ? null : await res.json() };
    },

    // ── OAuth (Google / LINE) ──────────────────────────
    async signInWithOAuth({ provider, options = {} }) {
      const redirectTo = options.redirectTo
        ?? `${window.location.origin}${window.location.pathname}?oauth_callback=1`;
      const url = `${supa.url}/auth/v1/authorize?provider=${provider}&redirect_to=${encodeURIComponent(redirectTo)}`;
      window.location.href = url;
      return { data: null, error: null };
    },

    // ── Handle OAuth callback (call on page load) ──────
    async handleOAuthCallback() {
      const hash = window.location.hash;
      if (!hash.includes("access_token")) return null;
      const params = new URLSearchParams(hash.replace("#","?"));
      const token = params.get("access_token");
      const refresh = params.get("refresh_token");
      if (!token) return null;
      supa._token = token;
      const session = { access_token: token, refresh_token: refresh };
      saveSession(session);
      // Clean URL
      window.history.replaceState({}, "", window.location.pathname);
      // Get user
      const res = await fetch(`${supa.url}/auth/v1/user`, {
        headers: supa._headers(),
      });
      const user = await res.json();
      return { user, session };
    },
  },

  // ── Data query builder ─────────────────────────────────────
  from(table) {
    return new SupaQuery(this.url, this.key, table, () => supa._token);
  },

  // ── RPC call ───────────────────────────────────────────────
  async rpc(fn, params = {}) {
    const res = await fetch(`${this.url}/rest/v1/rpc/${fn}`, {
      method: "POST",
      headers: supa._headers({ "Prefer": "return=representation" }),
      body: JSON.stringify(params),
    });
    const data = await res.json();
    return { data: res.ok ? data : null, error: res.ok ? null : data };
  },

  // ── Realtime channel ──────────────────────────────────────
  _channels: {},
  channel(name) {
    const ch = {
      _name:     name,
      _filters:  [],
      _handlers: {},
      on(event, filterOrHandler, handlerOrUndef) {
        // support: .on("INSERT", {schema,table,filter}, handler)
        //      or: .on("INSERT", handler)
        if (typeof filterOrHandler === "function") {
          this._handlers[event] = filterOrHandler;
        } else {
          this._filters.push({ event, ...filterOrHandler });
          if (typeof handlerOrUndef === "function") {
            this._handlers[event + JSON.stringify(filterOrHandler)] = handlerOrUndef;
          }
        }
        return this;
      },
      subscribe(statusCb) {
        // Use Supabase Realtime WebSocket
        const wsUrl = supa.url.replace("https://","wss://").replace("http://","ws://")
          + "/realtime/v1/websocket?apikey=" + supa.key;
        try {
          const ws = new WebSocket(wsUrl);
          ws.onopen = () => {
            statusCb?.("SUBSCRIBED");
            // Join each filter
            for (const f of this._filters) {
              ws.send(JSON.stringify({
                topic:   `realtime:${f.schema ?? "public"}:${f.table ?? "*"}:${f.filter ?? "*"}`,
                event:   "phx_join",
                payload: { config: { broadcast: { self: false }, postgres_changes: [f] } },
                ref:     "1",
              }));
            }
            // Generic broadcast join
            if (this._filters.length === 0) {
              ws.send(JSON.stringify({ topic: `realtime:${name}`, event: "phx_join", payload: {}, ref: "1" }));
            }
          };
          ws.onmessage = (e) => {
            try {
              const msg = JSON.parse(e.data);
              if (msg.event === "postgres_changes" && msg.payload?.data) {
                const d = msg.payload.data;
                const key = d.type + JSON.stringify({ schema: d.schema, table: d.table });
                const handler = this._handlers[d.type + JSON.stringify({ schema: d.schema, table: d.table })]
                  ?? this._handlers[d.type]
                  ?? this._handlers["*"];
                handler?.(d);
              }
            } catch(_) {}
          };
          ws.onerror  = () => statusCb?.("CHANNEL_ERROR");
          ws.onclose  = () => statusCb?.("CLOSED");
          supa._channels[name] = ws;
        } catch(e) {
          statusCb?.("CHANNEL_ERROR");
        }
        return this;
      },
    };
    return ch;
  },
  removeChannel(name) {
    const ws = supa._channels[name];
    if (ws) { try { ws.close(); } catch(_) {} delete supa._channels[name]; }
  },

  // ── Edge Function call ─────────────────────────────────────
  async functions(name, body = {}) {
    const res = await fetch(`${this.url}/functions/v1/${name}`, {
      method: "POST",
      headers: supa._headers(),
      body: JSON.stringify(body),
    });
    const data = await res.json();
    return { data: res.ok ? data : null, error: res.ok ? null : data };
  },

  // ── Storage upload ─────────────────────────────────────────
  async uploadFile(bucket, path, file) {
    const res = await fetch(`${this.url}/storage/v1/object/${bucket}/${path}`, {
      method: "POST",
      headers: { "apikey": this.key, "Authorization": `Bearer ${this._token ?? this.key}` },
      body: file,
    });
    const data = await res.json();
    return {
      data: res.ok ? { path, publicUrl: `${this.url}/storage/v1/object/public/${bucket}/${path}` } : null,
      error: res.ok ? null : data,
    };
  },
};

// Simple query builder class
class SupaQuery {
  constructor(url, key, table, getToken) {
    this._url = url; this._key = key;
    this._table = table; this._getToken = getToken;
    this._filters = []; this._select = "*";
    this._order = null; this._limit = null;
    this._single = false; this._method = "GET"; this._body = null;
    this._prefer = "return=representation";
  }
  select(cols) { this._select = cols; return this; }
  eq(col, val) { this._filters.push(`${col}=eq.${val}`); return this; }
  neq(col, val){ this._filters.push(`${col}=neq.${val}`); return this; }
  in(col, vals){ this._filters.push(`${col}=in.(${vals.join(",")})`); return this; }
  not(col, op, val){ this._filters.push(`${col}=not.${op}.${val ?? ""}`); return this; }
  order(col, { ascending = true } = {}) {
    this._order = `${col}=${ascending?"asc":"desc"}`; return this;
  }
  limit(n) { this._limit = n; return this; }
  single() { this._single = true; return this; }
  insert(data) { this._method = "POST"; this._body = data; return this; }
  update(data) { this._method = "PATCH"; this._body = data; return this; }
  upsert(data) { this._method = "POST"; this._body = data; this._prefer = "resolution=merge-duplicates,return=representation"; return this; }
  delete() { this._method = "DELETE"; return this; }
  onConflict(col) { this._prefer = `resolution=merge-duplicates,return=representation`; return this; }
  ignore() { this._prefer = "resolution=ignore-duplicates"; return this; }

  async _exec() {
    let url = `${this._url}/rest/v1/${this._table}?select=${encodeURIComponent(this._select)}`;
    for (const f of this._filters) url += `&${f}`;
    if (this._order) url += `&order=${this._order}`;
    if (this._limit) url += `&limit=${this._limit}`;

    const res = await fetch(url, {
      method: this._method,
      headers: {
        "Content-Type": "application/json",
        "apikey": this._key,
        "Authorization": `Bearer ${(this._getToken() ?? this._key)}`,
        "Prefer": this._prefer,
        ...(this._single ? { "Accept": "application/vnd.pgrst.object+json" } : {}),
      },
      body: this._body ? JSON.stringify(this._body) : undefined,
    });

    let data = null;
    try { data = res.status !== 204 ? await res.json() : null; } catch(_) {}
    return {
      data: res.ok ? data : null,
      error: res.ok ? null : data,
      count: parseInt(res.headers.get("content-range")?.split("/")[1] ?? "0"),
    };
  }
  then(resolve, reject) { return this._exec().then(resolve, reject); }
}

// ─── Session persistence helper ────────────────────────────────
function saveSession(session) {
  try { if (session) localStorage.setItem("sb_session", JSON.stringify(session)); } catch(_) {}
}
function clearSession() {
  try { localStorage.removeItem("sb_session"); } catch(_) {}
}

