/*
 * FeatureListCollapsible — Miller's Law: 7±2 items max visible
 * Hick's Law: "See all" reduces initial cognitive load
 */
function FeatureListCollapsible({ features, pkgColor, isPro, maxVisible = 6 }) {
  const [expanded, setExpanded] = useState(false);
  const shown    = expanded ? features : features.slice(0, maxVisible);
  const hasMore  = features.length > maxVisible;
  const textColor = isPro ? "#FFFFFF" : null;
  const mutedColor = isPro ? "rgba(255,255,255,0.5)" : null;
  return (
    <div style={{ marginTop: 16, paddingTop: 16, borderTop: `1px solid ${isPro ? "rgba(255,255,255,0.18)" : T.border}` }}>
      {shown.map((f, fi) => (
        <div key={fi} style={{ display: "flex", gap: 8, alignItems: "flex-start", marginBottom: 7 }}>
          <span style={{
            width: 16, height: 16, borderRadius: "50%", flexShrink: 0, marginTop: 2,
            display: "flex", alignItems: "center", justifyContent: "center",
            background: f.included ? (isPro ? "rgba(255,255,255,0.2)" : pkgColor + "18") : "transparent",
            fontSize: 9, fontWeight: 800,
            color: f.included ? (isPro ? "#fff" : pkgColor) : (isPro ? "rgba(255,255,255,0.2)" : T.border),
          }}>{f.included ? "✓" : "–"}</span>
          <div style={{ flex: 1, display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
            <span style={{
              fontSize: 12, lineHeight: 1.45, fontFamily: T.sans,
              color: f.included ? (textColor || T.muted2) : (mutedColor || T.muted),
              opacity: f.included ? 1 : 0.5,
              textDecoration: f.included ? "none" : "line-through",
            }}>{f.text}</span>
            {/* Feature tag badge */}
            {f.tag && f.tag !== "✓" && (
              <span style={{
                fontSize: 8, fontWeight: 700, fontFamily: T.mono,
                borderRadius: 4, padding: "1px 5px", flexShrink: 0,
                background: f.included
                  ? (isPro ? "rgba(255,255,255,0.18)" : pkgColor + "15")
                  : "rgba(220,38,38,0.08)",
                color: f.included
                  ? (isPro ? "rgba(255,255,255,0.85)" : pkgColor)
                  : T.muted,
                border: `1px solid ${f.included
                  ? (isPro ? "rgba(255,255,255,0.25)" : pkgColor + "30")
                  : T.border + "80"}`,
              }}>{f.tag}</span>
            )}
          </div>
        </div>
      ))}
      {hasMore && (
        <button onClick={() => setExpanded(e => !e)} style={{
          display: "flex", alignItems: "center", gap: 5, marginTop: 8,
          background: "none", border: "none", padding: "4px 0",
          color: isPro ? "rgba(255,255,255,0.7)" : pkgColor,
          fontSize: 11, fontFamily: T.sans, fontWeight: 600, cursor: "pointer",
          minHeight: "auto",
        }}>
          {expanded ? `▲ ซ่อน` : `▼ ดูทั้งหมด +${features.length - maxVisible}`}
        </button>
      )}
    </div>
  );
}

/* FormProgress — Zeigarnik Effect */
function FormProgress({ fields, values }) {
  const filled = fields.filter(f => values[f] && values[f].toString().length > 0).length;
  const pct    = Math.round((filled / fields.length) * 100);
  const color  = pct === 100 ? T.green : pct >= 50 ? T.gold : T.muted;
  return (
    <div style={{ marginBottom: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
        <span style={{ fontSize: 11, color: T.muted, fontFamily: T.sans }}>กรอกแล้ว {filled}/{fields.length} ช่อง</span>
        <span style={{ fontSize: 11, fontWeight: 700, color, fontFamily: T.mono }}>{pct}%</span>
      </div>
      <div style={{ height: 4, background: T.border, borderRadius: 2, overflow: "hidden" }}>
        <div style={{ height: "100%", borderRadius: 2, width: `${pct}%`, background: color, transition: "width 0.3s ease" }}/>
      </div>
    </div>
  );
}

