// ─── AUTH MODAL ───────────────────────────────────────────────
export function AuthModal({ mode: initMode = "login", onClose, onSuccess, selectedPkg }) {
  const [mode, setMode] = useState(initMode);
  const [form, setForm] = useState({ email: "", password: "", name: "", org: "", phone: "", confirmPassword: "" });
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [step, setStep] = useState(1);

  const set = (k) => (e) => setForm(f => ({ ...f, [k]: e.target.value }));

  const validate = () => {
    const errs = {};
    if (!form.email.includes("@")) errs.email = "รูปแบบอีเมลไม่ถูกต้อง";
    if (form.password.length < 8) errs.password = "รหัสผ่านต้องมีอย่างน้อย 8 ตัวอักษร";
    if (mode === "register") {
      if (!form.name) errs.name = "กรุณากรอกชื่อ-นามสกุล";
      if (!form.org) errs.org = "กรุณากรอกชื่อองค์กร";
      if (form.password !== form.confirmPassword) errs.confirmPassword = "รหัสผ่านไม่ตรงกัน";
    }
    return errs;
  };

  const handleSubmit = async () => {
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    try {
      if (mode === "register") {
        // Supabase sign-up — pass profile data in user_metadata
        const { data, error } = await supa.auth.signUp({
          email:    form.email,
          password: form.password,
          options:  {
            data: {
              full_name: form.name,
              org_name:  form.org,
              phone:     form.phone ?? "",
            },
          },
        });
        if (error) { setErrors({ email: error.error_description ?? error.message }); setLoading(false); return; }
        saveSession(data.session);
        // profile + org auto-created by handle_new_user() DB trigger
        onSuccess({
          id:    data.user?.id,
          name:  form.name,
          email: form.email,
          org:   form.org,
          plan:  "free",
        });
      } else {
        // Sign in
        const { data, error } = await supa.auth.signInWithPassword({
          email:    form.email,
          password: form.password,
        });
        if (error) { setErrors({ email: "อีเมลหรือรหัสผ่านไม่ถูกต้อง" }); setLoading(false); return; }
        saveSession(data.session);

        // Fetch profile + subscription
        const { data: profile } = await supa
          .from("profiles")
          .select("full_name, org_id, organizations(name), subscriptions(plan, status)")
          .eq("id", data.user.id)
          .single();

        const plan = profile?.subscriptions?.[0]?.plan ?? "free";
        onSuccess({
          id:    data.user.id,
          name:  profile?.full_name ?? form.email.split("@")[0],
          email: data.user.email,
          org:   profile?.organizations?.name ?? "—",
          plan,
          orgId: profile?.org_id,
        });

        // PLG event
        await supa.functions("plg-event", {
          event_name: "dashboard_opened",
          properties: { method: "login" },
        });
      }
    } catch (e) {
      setErrors({ email: "เกิดข้อผิดพลาด กรุณาลองใหม่" });
    }
    setLoading(false);
  };

  // Forgot password handler
  const handleForgot = async () => {
    if (!form.email) { setErrors({ email: "กรอกอีเมลก่อน" }); return; }
    await supa.auth.resetPasswordForEmail(form.email);
    alert("ส่งลิงก์รีเซ็ตรหัสผ่านไปที่ " + form.email + " แล้วครับ");
  };

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 1000,
      background: "rgba(13,27,62,0.6)", backdropFilter: "blur(8px)",
      display: "flex", alignItems: "center", justifyContent: "center",
      animation: "fadeIn 0.2s ease",
    }} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={{
        background: T.bg2, borderRadius: 20, padding: 36, width: "100%", maxWidth: 460,
        border: `1px solid ${T.border}`, boxShadow: `0 40px 100px rgba(0,0,0,0.6)`,
        animation: "fadeUp 0.35s ease",
      }}>
        {/* Header — tenant-aware */}
        {(() => {
          const tnt = useTenant?.() ?? null;
          const isTenant = tnt?.type === "tenant";
          return (
            <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 28 }}>
              <div>
                <Logo size={15} />
                {isTenant && (
                  <div style={{
                    marginTop: 8, fontSize: 11, color: T.teal, fontFamily: T.mono,
                    background: "rgba(2,132,199,0.08)", borderRadius: 6,
                    padding: "3px 10px", display: "inline-block",
                  }}>
                    🏢 {tnt.org_name}
                  </div>
                )}
                <div style={{ marginTop: 12, fontSize: 22, fontFamily: T.serif, fontWeight: 700, color: T.white }}>
                  {mode === "login" ? "ยินดีต้อนรับกลับ" : "สร้างบัญชีใหม่"}
                </div>
                <div style={{ fontSize: 13, color: T.muted, fontFamily: T.sans, marginTop: 4 }}>
                  {mode === "login"
                    ? (isTenant ? `เข้าสู่ระบบ ${tnt.org_name}` : "เข้าสู่ระบบเพื่อจัดการ BCMS ของคุณ")
                    : "เริ่มต้น 14 วันทดลองใช้ฟรี ไม่ต้องใช้บัตรเครดิต"
                  }
                </div>
              </div>
              <button onClick={onClose} style={{ background: "none", border: "none", color: T.muted, fontSize: 20, lineHeight: 1 }}>✕</button>
            </div>
          );
        })()}

        {/* Zeigarnik Effect — show what they've chosen to complete */}
        {selectedPkg && (
          <div style={{
            background: T.goldBg, border: `1px solid ${T.gold}50`, borderRadius: 12,
            padding: "12px 16px", marginBottom: 20, display: "flex", gap: 12, alignItems: "center",
            boxShadow: "var(--shadow-sm)",
          }}>
            <div style={{ width: 36, height: 36, borderRadius: 10, background: T.gold + "20", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              <span style={{ fontSize: 18 }}>{PACKAGES.find(p => p.id === selectedPkg)?.icon}</span>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 10, color: T.muted, fontFamily: T.mono, letterSpacing: 1 }}>SELECTED PLAN</div>
              <div style={{ fontSize: 14, fontWeight: 700, color: T.gold, fontFamily: T.sans }}>
                {PACKAGES.find(p => p.id === selectedPkg)?.name}
                {PACKAGES.find(p => p.id === selectedPkg)?.price > 0 &&
                  <span style={{ fontSize: 12, fontWeight: 400, color: T.muted, marginLeft: 6 }}>
                    ฿{PACKAGES.find(p => p.id === selectedPkg)?.price.toLocaleString()}/เดือน
                  </span>
                }
              </div>
            </div>
            {/* Peak-End Rule — positive reinforcement */}
            <span style={{ fontSize: 20 }}>✅</span>
          </div>
        )}
        {/* Zeigarnik — form progress indicator for register */}
        {mode === "register" && (
          <FormProgress
            fields={["name","org","email","password","confirmPassword"]}
            values={form}
          />
        )}

        {/* Form */}
        {mode === "register" && (
          <>
            <Input label="ชื่อ-นามสกุล" value={form.name} onChange={set("name")}
              placeholder="สมชาย ใจดี" icon="👤" error={errors.name} />
            <Input label="ชื่อองค์กร / บริษัท" value={form.org} onChange={set("org")}
              placeholder="บริษัท ABC จำกัด" icon="🏢" error={errors.org} />
          </>
        )}
        <Input label="อีเมล" type="email" value={form.email} onChange={set("email")}
          placeholder="you@company.com" icon="✉" error={errors.email} />
        <Input label="รหัสผ่าน" type="password" value={form.password} onChange={set("password")}
          placeholder={mode === "register" ? "อย่างน้อย 8 ตัวอักษร" : "••••••••"} icon="🔒"
          error={errors.password} />
        {mode === "register" && (
          <Input label="ยืนยันรหัสผ่าน" type="password" value={form.confirmPassword}
            onChange={set("confirmPassword")} placeholder="••••••••" icon="🔒"
            error={errors.confirmPassword} />
        )}

        {mode === "login" && (
          <div style={{ textAlign: "right", marginTop: -8, marginBottom: 16 }}>
            <button onClick={handleForgot} style={{ background: "none", border: "none", color: T.gold, fontSize: 12, fontFamily: T.sans }}>
              ลืมรหัสผ่าน?
            </button>
          </div>
        )}

        <Btn full onClick={handleSubmit} disabled={loading}>
          {loading ? (
            <span style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ width: 14, height: 14, border: "2px solid #FFFFFF", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.6s linear infinite", display: "inline-block" }} />
              กำลังดำเนินการ...
            </span>
          ) : mode === "login" ? "เข้าสู่ระบบ" : "สร้างบัญชีฟรี"}
        </Btn>

        {/* Hick's Law: 2 OAuth options (reduce password friction) */}
        <Divider label="หรือเข้าสู่ระบบด้วย" />
        <OAuthButtons label={mode === "login" ? "เข้าสู่ระบบ" : "สมัครสมาชิก"} />

        {/* Serial Position — switch link at end (primacy already used by heading) */}
        <div style={{
          textAlign: "center", fontSize: 13, color: T.muted, fontFamily: T.sans,
          padding: "14px 0 0", borderTop: `1px solid ${T.border}`, marginTop: 4,
        }}>
          {mode === "login" ? "ยังไม่มีบัญชี?" : "มีบัญชีแล้ว?"}
          {" "}
          <button onClick={() => { setMode(mode === "login" ? "register" : "login"); setErrors({}); }}
            style={{ background: "none", border: "none", color: T.gold, fontWeight: 700, fontSize: 13, fontFamily: T.sans, minHeight: "auto" }}>
            {mode === "login" ? "สมัครสมาชิกฟรี →" : "เข้าสู่ระบบ"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── PAYMENT MODAL ────────────────────────────────────────────
export function PaymentModal({ pkg, billing, user, onClose, onSuccess }) {
  const [selectedBank, setSelectedBank] = useState(0);
  const [step, setStep] = useState(1); // 1=details, 2=confirm
  const [copied, setCopied] = useState(null);
  const [slipUploaded, setSlipUploaded] = useState(false);
  const [loading, setLoading] = useState(false);
  const amount = billing === "annual" ? pkg.priceAnnual * 12 : pkg.price;
  const period = billing === "annual" ? "12 เดือน (ประหยัด 20%)" : "1 เดือน";

  const copyText = (text, key) => {
    navigator.clipboard?.writeText(text).catch(() => {});
    setCopied(key);
    setTimeout(() => setCopied(null), 2000);
  };

  const [slipPath,       setSlipPath]       = useState("");
  const [slipName,       setSlipName]       = useState("");
  const [uploadProgress, setUploadProgress] = useState(0);

  const handleConfirm = async () => {
    if (!slipUploaded || !slipPath) { alert("กรุณาแนบสลิปการโอนเงินก่อน"); return; }
    setLoading(true);
    const { data, error } = await supa.functions("payment-webhook", {
      plan:      pkg.id,
      billing,
      slip_path: slipPath,
      slip_name: slipName,
    });
    setLoading(false);
    if (error) { alert("เกิดข้อผิดพลาด: " + (error.error ?? "กรุณาติดต่อ 081-781-7773")); return; }
    onSuccess(data?.order_ref);
  };

  const bank = BANK_ACCOUNTS[selectedBank];

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 1000,
      background: "rgba(13,27,62,0.65)", backdropFilter: "blur(8px)",
      display: "flex", alignItems: "center", justifyContent: "center",
      animation: "fadeIn 0.2s ease", overflowY: "auto", padding: 20,
    }} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={{
        background: T.bg2, borderRadius: 20, padding: 36, width: "100%", maxWidth: 540,
        border: `1px solid ${T.border}`, boxShadow: "0 40px 100px rgba(0,0,0,0.7)",
        animation: "fadeUp 0.35s ease",
      }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24 }}>
          <div>
            <div style={{ fontSize: 11, color: T.muted, fontFamily: T.mono, letterSpacing: 2, marginBottom: 6 }}>
              STEP {step} OF 2 — PAYMENT
            </div>
            <div style={{ fontSize: 22, fontFamily: T.serif, fontWeight: 700, color: T.white }}>
              {step === 1 ? "รายละเอียดการชำระเงิน" : "ยืนยันการชำระเงิน"}
            </div>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: T.muted, fontSize: 20 }}>✕</button>
        </div>

        {/* Order Summary */}
        <div style={{ background: T.bg3, borderRadius: 12, padding: 18, marginBottom: 24, border: `1px solid ${T.border}` }}>
          <div style={{ fontSize: 11, color: T.muted, fontFamily: T.mono, letterSpacing: 1, marginBottom: 12 }}>ORDER SUMMARY</div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontSize: 13, color: T.muted2, fontFamily: T.sans }}>แพ็กเกจ</span>
            <span style={{ fontSize: 13, fontWeight: 600, color: T.white, fontFamily: T.sans }}>
              {pkg.name} Plan
            </span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontSize: 13, color: T.muted2, fontFamily: T.sans }}>ระยะเวลา</span>
            <span style={{ fontSize: 13, color: T.white, fontFamily: T.sans }}>{period}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontSize: 13, color: T.muted2, fontFamily: T.sans }}>ภาษีมูลค่าเพิ่ม (7%)</span>
            <span style={{ fontSize: 13, color: T.white, fontFamily: T.sans }}>
              ฿{Math.round(amount * 0.07).toLocaleString()}
            </span>
          </div>
          <div style={{ height: 1, background: T.border, margin: "12px 0" }} />
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontSize: 14, fontWeight: 700, color: T.white, fontFamily: T.sans }}>ยอดรวมทั้งสิ้น</span>
            <span style={{ fontSize: 22, fontWeight: 700, fontFamily: T.serif, color: T.gold }}>
              ฿{Math.round(amount * 1.07).toLocaleString()}
            </span>
          </div>
          <div style={{ marginTop: 8 }}>
            <div style={{ fontSize: 11, color: T.muted, fontFamily: T.sans }}>
              ชื่อบัญชีองค์กร: <strong style={{ color: T.white }}>{user.org}</strong> · อีเมล: {user.email}
            </div>
          </div>
        </div>

        {step === 1 && (
          <>
            {/* Bank Details */}
            <div style={{ background: T.bg3, borderRadius: 14, padding: 20, marginBottom: 20, border: `1px solid ${T.border}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
                <div style={{ width: 36, height: 36, borderRadius: 8, background: bank.color, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <span style={{ fontSize: 11, fontWeight: 800, color: "#fff", fontFamily: T.mono }}>{bank.logo}</span>
                </div>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: T.white, fontFamily: T.sans }}>{bank.bank}</div>
                  <div style={{ fontSize: 10, color: T.muted, fontFamily: T.sans }}>{bank.abbr} — Corporate Account</div>
                </div>
              </div>

              {[
                { label: "ชื่อบัญชี", value: bank.name, key: "name" },
                { label: "เลขที่บัญชี", value: bank.number, key: "number" },
                { label: "ยอดโอน (รวม VAT)", value: `฿${Math.round(amount * 1.07).toLocaleString()}`, key: "amount" },
              ].map(row => (
                <div key={row.key} style={{
                  display: "flex", justifyContent: "space-between", alignItems: "center",
                  padding: "10px 0", borderBottom: `1px solid ${T.border}`,
                }}>
                  <span style={{ fontSize: 12, color: T.muted, fontFamily: T.sans }}>{row.label}</span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ fontSize: 13, fontWeight: 600, color: T.white, fontFamily: row.key === "number" ? T.mono : T.sans }}>
                      {row.value}
                    </span>
                    <button onClick={() => copyText(row.value, row.key)} style={{
                      background: copied === row.key ? T.goldBg : T.bg4,
                      border: `1px solid ${copied === row.key ? T.gold : T.border}`,
                      borderRadius: 6, padding: "3px 8px", color: copied === row.key ? T.gold : T.muted,
                      fontSize: 10, fontFamily: T.sans,
                    }}>
                      {copied === row.key ? "✓ คัดลอก" : "คัดลอก"}
                    </button>
                  </div>
                </div>
              ))}
              <div style={{ marginTop: 12, padding: "10px 14px", background: T.goldBg, borderRadius: 8, border: `1px solid ${T.gold}30` }}>
                <div style={{ fontSize: 11, color: T.gold, fontFamily: T.sans }}>
                  ⚠ หมายเหตุ: กรุณาโอนตามยอดที่ระบุไว้อย่างแม่นยำ และระบุชื่อองค์กรของท่านในช่องหมายเหตุ
                </div>
              </div>
            </div>

            {/* Slip Upload Simulation */}
            <div style={{ marginBottom: 20 }}>
              <div style={{ fontSize: 12, fontWeight: 500, color: T.muted2, fontFamily: T.sans, marginBottom: 8 }}>
                แนบหลักฐานการโอนเงิน (Slip)
              </div>
              <div
                onClick={async () => {
                  const fileInput = document.createElement("input");
                  fileInput.type = "file";
                  fileInput.accept = "image/*,application/pdf";
                  fileInput.onchange = async (e) => {
                    const file = e.target.files?.[0];
                    if (!file) return;
                    setUploadProgress(10);
                    const orgId  = user?.orgId ?? "demo-org";
                    const path   = `${orgId}/slips/${Date.now()}-${file.name}`;
                    setUploadProgress(40);
                    const { data: uploaded, error: upErr } = await supa.uploadFile(
                      "payment-slips", path, file
                    );
                    if (upErr) { alert("อัปโหลดล้มเหลว: " + (upErr.message ?? "Storage error")); setUploadProgress(0); return; }
                    setUploadProgress(80);
                    setSlipPath(path);
                    setSlipName(file.name);
                    setSlipUploaded(true);
                    setUploadProgress(100);
                    setTimeout(() => setUploadProgress(0), 600);
                  };
                  fileInput.click();
                }}
                style={{
                  border: `2px dashed ${slipUploaded ? T.green : T.border2}`,
                  borderRadius: 12, padding: "24px 20px", textAlign: "center",
                  background: slipUploaded ? "rgba(16,185,129,0.05)" : T.bg3,
                  cursor: "pointer", transition: "all 0.2s",
                }}>
                {slipUploaded ? (
                  <div>
                    <div style={{ fontSize: 28, marginBottom: 6 }}>✅</div>
                    <div style={{ fontSize: 13, color: T.green, fontWeight: 600, fontFamily: T.sans }}>slip_transfer.jpg</div>
                    <div style={{ fontSize: 11, color: T.muted, fontFamily: T.sans, marginTop: 2 }}>คลิกเพื่อเปลี่ยนไฟล์</div>
                  </div>
                ) : (
                  <div>
                    <div style={{ fontSize: 28, marginBottom: 6 }}>📄</div>
                    <div style={{ fontSize: 13, color: T.muted2, fontFamily: T.sans }}>คลิกเพื่ออัปโหลด Slip</div>
                    <div style={{ fontSize: 11, color: T.muted, fontFamily: T.sans, marginTop: 2 }}>PNG, JPG หรือ PDF (สูงสุด 5MB)</div>
                  </div>
                )}
              </div>
            </div>

            <Btn full onClick={() => setStep(2)} disabled={!slipUploaded}>
              ดำเนินการต่อ →
            </Btn>
          </>
        )}

        {step === 2 && (
          <>
            <div style={{ background: T.bg3, borderRadius: 12, padding: 20, marginBottom: 20, border: `1px solid ${T.border}` }}>
              <div style={{ fontSize: 11, color: T.muted, fontFamily: T.mono, letterSpacing: 1, marginBottom: 12 }}>ยืนยันข้อมูล</div>
              {[
                { l: "ชื่อ-นามสกุล", v: user.name },
                { l: "อีเมล", v: user.email },
                { l: "องค์กร", v: user.org },
                { l: "แพ็กเกจ", v: `${pkg.name} (${billing === "annual" ? "รายปี" : "รายเดือน"})` },
                { l: "ธนาคาร", v: BANK_ACCOUNTS[selectedBank].bank },
                { l: "ยอดที่โอน", v: `฿${Math.round(amount * 1.07).toLocaleString()} (รวม VAT)` },
              ].map(r => (
                <div key={r.l} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: `1px solid ${T.border}` }}>
                  <span style={{ fontSize: 12, color: T.muted, fontFamily: T.sans }}>{r.l}</span>
                  <span style={{ fontSize: 12, fontWeight: 600, color: T.white, fontFamily: T.sans }}>{r.v}</span>
                </div>
              ))}
            </div>

            <div style={{ padding: "12px 16px", background: "rgba(16,185,129,0.08)", borderRadius: 10, border: `1px solid ${T.green}30`, marginBottom: 20 }}>
              <div style={{ fontSize: 12, color: T.green, fontFamily: T.sans, lineHeight: 1.6 }}>
                ✓ ทีมงานจะตรวจสอบการชำระเงินภายใน 2-4 ชั่วโมง (วันทำการ 09:00–18:00 น.)
สอบถาม: Tel. 081-781-7773 (Buff) · Line: @Buffy20 · support@b-tctraining.com<br />
                ✓ เมื่อยืนยันแล้ว บัญชีของท่านจะถูกเปิดใช้งานทันที และได้รับแจ้งทางอีเมล
              </div>
            </div>

            <div style={{ display: "flex", gap: 10 }}>
              <Btn variant="ghost" onClick={() => setStep(1)}>← ย้อนกลับ</Btn>
              <Btn full onClick={handleConfirm} disabled={loading}>
                {loading ? (
                  <span style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ width: 14, height: 14, border: "2px solid #FFFFFF", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.6s linear infinite", display: "inline-block" }} />
                    กำลังส่งข้อมูล...
                  </span>
                ) : "ยืนยันการชำระเงิน ✓"}
              </Btn>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

