function NotificationCenter({ orgId }) {
  const [open,   setOpen]   = useState(false);
  const [notifs, setNotifs] = useState([
    { id:1, icon:"✅", title:"ยินดีต้อนรับสู่ B.Training BCMS-Automate", time:"เมื่อกี้", read:false },
  ]);
  const unread = notifs.filter(n => !n.read).length;

  // Realtime: listen for new PLG events for this org
  useEffect(() => {
    if (!orgId) return;
    const ch = supa.channel("notifications-" + orgId)
      .on("postgres_changes", {
        event: "INSERT", schema: "public", table: "plg_events",
        filter: `org_id=eq.${orgId}`,
      }, (payload) => {
        const evt = payload.new ?? payload;
        const labels = {
          payment_submitted:     { icon:"💳", title:"ส่งหลักฐานการชำระเงินแล้ว" },
          subscription_activated:{ icon:"🚀", title:"Plan อัปเกรดสำเร็จ!" },
          invite_accepted:       { icon:"👥", title:"สมาชิกใหม่เข้าร่วมทีม" },
          bia_created:           { icon:"◇", title:"สร้าง BIA Process ใหม่แล้ว" },
          risk_added:            { icon:"△", title:"เพิ่ม Risk Item ใหม่แล้ว" },
          onboarding_completed:  { icon:"🏆", title:"คุณ Onboard เสร็จสมบูรณ์!" },
        };
        const cfg = labels[evt.event_name] ?? { icon:"🔔", title: evt.event_name };
        setNotifs(ns => [{
          id: Date.now(), icon: cfg.icon, title: cfg.title,
          time: "เมื่อกี้", read: false, event: evt.event_name,
        }, ...ns.slice(0, 19)]);
      })
      .subscribe();
    return () => supa.removeChannel("notifications-" + orgId);
  }, [orgId]);

  const markAllRead = () => setNotifs(ns => ns.map(n => ({ ...n, read: true })));

  return (
    <div style={{ position:"relative" }}>
      <button
        onClick={() => { setOpen(o => !o); if (!open) markAllRead(); }}
        style={{
          position:"relative", width:40, height:40, borderRadius:10,
          background: open ? T.bg3 : "transparent",
          border:`1.5px solid ${open ? T.border2 : T.border}`,
          display:"flex", alignItems:"center", justifyContent:"center",
          cursor:"pointer", transition:"all 0.15s",
        }}
        onMouseEnter={e => { if (!open) { e.currentTarget.style.background = T.bg3; }}}
        onMouseLeave={e => { if (!open) { e.currentTarget.style.background = "transparent"; }}}
      >
        <span style={{ fontSize:16 }}>🔔</span>
        {unread > 0 && (
          <span style={{
            position:"absolute", top:-3, right:-3,
            width:16, height:16, borderRadius:"50%",
            background:T.red, color:"#fff",
            fontSize:9, fontWeight:800, fontFamily:T.mono,
            display:"flex", alignItems:"center", justifyContent:"center",
            border:`2px solid ${T.bg2}`,
            animation: unread > 0 ? "pulse-ring 2s ease infinite" : "none",
          }}>{unread > 9 ? "9+" : unread}</span>
        )}
      </button>

      {open && (
        <div style={{
          position:"absolute", top:48, right:0, width:320,
          background:T.bg2, borderRadius:16,
          border:`1px solid ${T.border}`,
          boxShadow:"var(--shadow-xl)",
          zIndex:9999, animation:"fadeUp 0.2s cubic-bezier(0.4,0,0.2,1)",
          overflow:"hidden",
        }}>
          {/* Header */}
          <div style={{ padding:"14px 16px 10px", display:"flex", alignItems:"center", justifyContent:"space-between",
            borderBottom:`1px solid ${T.border}` }}>
            <span style={{ fontSize:13, fontWeight:700, color:T.white, fontFamily:T.sans }}>
              การแจ้งเตือน
            </span>
            {/* Realtime indicator */}
            <div style={{ display:"flex", alignItems:"center", gap:5 }}>
              <span style={{ width:6, height:6, borderRadius:"50%", background:T.green,
                animation:"pulse-ring 2s ease infinite" }}/>
              <span style={{ fontSize:9, color:T.green, fontFamily:T.mono, letterSpacing:1 }}>LIVE</span>
            </div>
          </div>

          {/* Notification list */}
          <div style={{ maxHeight:320, overflowY:"auto" }}>
            {notifs.length === 0 ? (
              <div style={{ padding:24, textAlign:"center", color:T.muted, fontSize:13, fontFamily:T.sans }}>
                ยังไม่มีการแจ้งเตือน
              </div>
            ) : notifs.map(n => (
              <div key={n.id} style={{
                display:"flex", gap:12, alignItems:"flex-start",
                padding:"12px 16px",
                background: n.read ? "transparent" : T.goldBg + "60",
                borderBottom:`1px solid ${T.border}`,
                transition:"background 0.2s",
              }}>
                <div style={{ width:32, height:32, borderRadius:8, background:T.bg3,
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:16, flexShrink:0 }}>{n.icon}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:12, fontWeight:600, color:T.white, fontFamily:T.sans,
                    lineHeight:1.3, marginBottom:3 }}>{n.title}</div>
                  <div style={{ fontSize:10, color:T.muted, fontFamily:T.sans }}>{n.time}</div>
                </div>
                {!n.read && (
                  <span style={{ width:7, height:7, borderRadius:"50%", background:T.gold,
                    flexShrink:0, marginTop:4 }}/>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}


