const ISO_22301_CLAUSES = [
  { id:"4", title:"บริบทขององค์กร", subs:["4.1 องค์กรและบริบท","4.2 ผู้มีส่วนได้เสีย","4.3 ขอบเขต BCMS","4.4 ระบบ BCMS"] },
  { id:"5", title:"ภาวะผู้นำ", subs:["5.1 ภาวะผู้นำและความมุ่งมั่น","5.2 นโยบาย BCM","5.3 บทบาทและหน้าที่"] },
  { id:"6", title:"การวางแผน", subs:["6.1 ความเสี่ยงและโอกาส","6.2 วัตถุประสงค์ BCM","6.3 การวางแผนการเปลี่ยนแปลง"] },
  { id:"7", title:"การสนับสนุน", subs:["7.1 ทรัพยากร","7.2 ความสามารถ","7.3 ความตระหนัก","7.4 การสื่อสาร","7.5 เอกสารสารสนเทศ"] },
  { id:"8", title:"การปฏิบัติการ", subs:["8.1 การวางแผนปฏิบัติการ","8.2 การประเมิน BCM","8.3 กลยุทธ์ความต่อเนื่อง","8.4 แผนความต่อเนื่อง","8.5 การออกกำลังกายและทดสอบ"] },
  { id:"9", title:"การประเมินสมรรถนะ", subs:["9.1 การติดตามและวัดผล","9.2 Audit ภายใน","9.3 ทบทวนโดยผู้บริหาร"] },
  { id:"10", title:"การปรับปรุง", subs:["10.1 ความไม่สอดคล้อง","10.2 การปรับปรุงอย่างต่อเนื่อง"] },
];

function ClausePage({ orgId, pkg, onUpgrade }) {
  const [status, setStatus] = useState({}); // clauseId -> 'compliant'|'partial'|'gap'|'na'
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Load clause status from org_settings or a dedicated table
    setLoading(false);
    // TODO: load from supabase clause_tracker table (migration 004)
  }, [orgId]);

  const toggle = async (sub) => {
    const order = ["gap", "partial", "compliant", "na"];
    const next  = order[(order.indexOf(status[sub]||"gap")+1)%4];
    setStatus(s => ({ ...s, [sub]: next }));
    // Persist to Supabase
    supa.rpc("upsert_clause_status", {
      p_org_id: orgId, p_clause: sub, p_status: next,
    }).catch(() => {});
  };

  // Load persisted clause status on mount
  useEffect(() => {
    if (!orgId) return;
    supa.from("clause_tracker").select("clause_ref,status").eq("org_id", orgId)
      .then(({ data }) => {
        if (data?.length) {
          const m = {};
          data.forEach(r => { m[r.clause_ref] = r.status; });
          setStatus(m);
        }
      }).catch(() => {});
  }, [orgId]);

  const statusCfg = {
    compliant: { color:T.green,  label:"✓ Compliant",  bg:T.green+"12" },
    partial:   { color:T.amber,  label:"~ Partial",    bg:T.amber+"12" },
    gap:       { color:T.red,    label:"✕ Gap",         bg:T.red+"12"  },
    na:        { color:T.muted,  label:"— N/A",         bg:T.bg3       },
  };

  const allSubs = ISO_22301_CLAUSES.flatMap(c => c.subs);
  const compliant = allSubs.filter(s => status[s]==="compliant").length;
  const pct = Math.round((compliant/allSubs.length)*100);

  return (
    <FeatureGate featureId="bcplan" userPkg={pkg} onUpgrade={onUpgrade}>
      <div style={{ animation:"fadeUp 0.4s ease" }}>
        <div style={{ marginBottom:20 }}>
          <div style={{ fontSize:20, fontFamily:T.serif, fontWeight:800, color:T.white }}>☰ Clause Tracker ISO 22301:2019</div>
          <div style={{ fontSize:12, color:T.muted, fontFamily:T.sans, marginTop:2 }}>
            ติดตามความสอดคล้องทุก Clause · {compliant}/{allSubs.length} Compliant ({pct}%)
          </div>
        </div>
        {/* Progress bar */}
        <div style={{ background:T.bg2,borderRadius:12,padding:"14px 18px",marginBottom:20,border:`1px solid ${T.border}` }}>
          <div style={{ display:"flex",justifyContent:"space-between",marginBottom:8 }}>
            <span style={{ fontSize:12,fontWeight:700,color:T.white,fontFamily:T.sans }}>Overall Compliance</span>
            <span style={{ fontSize:14,fontWeight:800,color:T.gold,fontFamily:T.mono }}>{pct}%</span>
          </div>
          <div style={{ height:10,background:T.bg3,borderRadius:5,overflow:"hidden" }}>
            <div style={{ height:"100%",width:pct+"%",background:`linear-gradient(90deg,${T.gold},${T.green})`,
              borderRadius:5,transition:"width 0.6s" }}/>
          </div>
          <div style={{ display:"flex",gap:12,marginTop:8 }}>
            {Object.entries(statusCfg).map(([k,c]) => (
              <span key={k} style={{ fontSize:10,color:c.color,fontFamily:T.sans }}>
                {c.label}: {allSubs.filter(s=>(status[s]||"gap")===k).length}
              </span>
            ))}
          </div>
        </div>
        {/* Clause list */}
        {ISO_22301_CLAUSES.map(clause => (
          <ModCard key={clause.id} style={{ marginBottom:12 }}>
            <div style={{ padding:"12px 16px",borderBottom:`1px solid ${T.border}`,
              display:"flex",alignItems:"center",gap:10 }}>
              <span style={{ fontSize:11,fontWeight:800,color:T.gold,fontFamily:T.mono,
                background:T.goldBg,borderRadius:4,padding:"2px 8px" }}>Clause {clause.id}</span>
              <span style={{ fontSize:13,fontWeight:700,color:T.white,fontFamily:T.sans }}>{clause.title}</span>
            </div>
            {clause.subs.map(sub => {
              const st = status[sub] || "gap";
              const cfg = statusCfg[st];
              return (
                <div key={sub} onClick={() => toggle(sub)}
                  style={{ display:"flex",alignItems:"center",gap:12,padding:"10px 16px",
                    borderBottom:`1px solid ${T.border}`,cursor:"pointer",transition:"background 0.1s" }}
                  onMouseEnter={e => e.currentTarget.style.background=T.bg3}
                  onMouseLeave={e => e.currentTarget.style.background="transparent"}>
                  <span style={{ background:cfg.bg,color:cfg.color,borderRadius:4,
                    padding:"2px 8px",fontSize:10,fontWeight:700,fontFamily:T.mono,
                    whiteSpace:"nowrap",flexShrink:0 }}>{cfg.label}</span>
                  <span style={{ fontSize:12,color:T.muted2,fontFamily:T.sans }}>{sub}</span>
                </div>
              );
            })}
          </ModCard>
        ))}
      </div>
    </FeatureGate>
  );
}

/* ─────────────────────────────────────────────────────────
   MODULE 5: SCCM — Supply Chain  (Professional+)
   ───────────────────────────────────────────────────────── */
function SCCMPage({ orgId, pkg, onUpgrade }) {
  const [suppliers, setSuppliers] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [drawer, setDrawer]       = useState(false);
  const [form, setForm]           = useState({ name:"", category:"", criticality:3, country:"Thailand", notes:"" });
  const [saving, setSaving]       = useState(false);

  const load = async () => {
    setLoading(true);
    const { data } = await supa.from("supply_chain_items")
      .select("id,name,category,criticality,country,status,last_assessment")
      .eq("org_id", orgId).order("criticality", { ascending: false });
    setSuppliers(data ?? []);
    setLoading(false);
  };

  useEffect(() => { if (orgId) load(); }, [orgId]);

  const handleSave = async () => {
    if (!form.name) return;
    setSaving(true);
    await supa.from("supply_chain_items").insert({ ...form, org_id: orgId, criticality: Number(form.criticality) });
    setSaving(false); setDrawer(false);
    setForm({ name:"",category:"",criticality:3,country:"Thailand",notes:"" });
    load();
  };

  const critColor = (c) => c>=5?T.red:c>=4?T.amber:c>=3?T.gold:T.green;

  return (
    <FeatureGate featureId="sccm" userPkg={pkg} onUpgrade={onUpgrade}>
      <div style={{ animation:"fadeUp 0.4s ease" }}>
        <div style={{ display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20 }}>
          <div>
            <div style={{ fontSize:20,fontFamily:T.serif,fontWeight:800,color:T.white }}>⛓ Supply Chain Module</div>
            <div style={{ fontSize:12,color:T.muted,fontFamily:T.sans,marginTop:2 }}>ISO/TS 22318:2015 · {suppliers.length} Suppliers</div>
          </div>
          <Btn size="sm" onClick={()=>setDrawer(true)} disabled={loading}>+ เพิ่ม Supplier</Btn>
        </div>
        <ModCard>
          {loading ? <div style={{padding:32,textAlign:"center"}}><span style={{width:20,height:20,border:`2px solid ${T.border}`,borderTopColor:T.gold,borderRadius:"50%",animation:"spin 0.7s linear infinite",display:"inline-block"}}/></div>
            : suppliers.length===0 ? <EmptyState icon="⛓" title="ยังไม่มี Supplier" desc="เพิ่ม Supplier เพื่อวิเคราะห์ Supply Chain Continuity ตาม ISO/TS 22318" cta="+ เพิ่ม Supplier แรก" onCta={()=>setDrawer(true)} />
            : <DataTable
                cols={[
                  { key:"name", label:"ชื่อ Supplier" },
                  { key:"category", label:"ประเภท" },
                  { key:"country", label:"ประเทศ" },
                  { key:"criticality", label:"Criticality",
                    render: v => <span style={{background:critColor(v)+"18",color:critColor(v),borderRadius:4,padding:"2px 8px",fontSize:11,fontWeight:700,fontFamily:T.mono}}>{v}</span> },
                  { key:"status", label:"Status",
                    render: v => <span style={{fontSize:10,fontFamily:T.mono,color:v==="approved"?T.green:T.amber}}>{(v||"pending").toUpperCase()}</span> },
                ]}
                rows={suppliers}
              />
          }
        </ModCard>
        <Drawer title="เพิ่ม Supplier" open={drawer} onClose={()=>setDrawer(false)}>
          {[{ l:"ชื่อบริษัท *", k:"name", placeholder:"ABC Co., Ltd." },
            { l:"ประเภทสินค้า/บริการ", k:"category", placeholder:"Raw Material, IT Services..." },
            { l:"ประเทศ", k:"country", placeholder:"Thailand" },
            { l:"หมายเหตุ", k:"notes", placeholder:"ข้อมูลเพิ่มเติม" },
          ].map(f => (
            <div key={f.k} style={{marginBottom:14}}>
              <label style={{fontSize:12,fontWeight:600,color:T.muted2,fontFamily:T.sans,display:"block",marginBottom:5}}>{f.l}</label>
              <input value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))} placeholder={f.placeholder}
                style={{width:"100%",padding:"9px 12px",background:T.bg3,border:`1px solid ${T.border}`,borderRadius:8,color:T.white,fontSize:13,fontFamily:T.sans,boxSizing:"border-box"}}/>
            </div>
          ))}
          <div style={{marginBottom:20}}>
            <label style={{fontSize:12,fontWeight:600,color:T.muted2,fontFamily:T.sans,display:"block",marginBottom:5}}>
              Criticality — ปัจจุบัน: <strong style={{color:critColor(form.criticality)}}>{form.criticality}</strong>
            </label>
            <input type="range" min={1} max={5} value={form.criticality}
              onChange={e=>setForm(p=>({...p,criticality:Number(e.target.value)}))}
              style={{width:"100%",accentColor:T.gold}}/>
          </div>
          <Btn full onClick={handleSave} disabled={saving||!form.name}>{saving?"กำลังบันทึก...":"บันทึก Supplier"}</Btn>
        </Drawer>
      </div>
    </FeatureGate>
  );
}

