/*
 * SuccessModal — Peak-End Rule:
 * The "end" of the user journey must be the most positive moment.
 * Celebrate the achievement, show next steps (reduces anxiety),
 * and give a tangible artifact (order number) to reinforce trust.
 * Serial Position: most important info first (confirmation),
 * actionable CTA last (recency).
 */
export function SuccessModal({ pkg, onContinue }) {
  const pkgData  = PACKAGES.find(p => p.id === pkg) || PACKAGES[1];
  const orderId  = "#ORD-" + Date.now().toString().slice(-8);
  const [step, setStep] = useState(0);

  /* Doherty Threshold: staggered reveal makes success feel alive */
  useEffect(() => {
    const t = setTimeout(() => setStep(1), 400);
    return () => clearTimeout(t);
  }, []);

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 1000,
      background: "rgba(13,27,62,0.65)", backdropFilter: "blur(10px)",
      display: "flex", alignItems: "center", justifyContent: "center",
      animation: "fadeIn 0.25s ease",
    }}>
      <div style={{
        background: T.bg2, borderRadius: 28, padding: "48px 40px", maxWidth: 480, width: "calc(100% - 32px)",
        border: `1px solid ${T.border}`,
        boxShadow: "var(--shadow-xl)",
        textAlign: "center", animation: "fadeUp 0.4s cubic-bezier(0.4,0,0.2,1)",
        position: "relative", overflow: "hidden",
      }}>
        {/* Decorative top strip — Von Restorff: plan color */}
        <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 5,
          background: `linear-gradient(90deg, ${pkgData.color}, ${T.teal})` }}/>

        {/* Peak moment — big celebration icon */}
        <div style={{ fontSize: 72, lineHeight: 1, marginBottom: 20,
          animation: "pulse-ring 2s ease-in-out infinite",
          filter: "drop-shadow(0 4px 16px rgba(21,101,192,0.3))" }}>
          🎉
        </div>

        {/* Serial Position: headline first */}
        <div style={{ fontSize: 28, fontFamily: T.serif, fontWeight: 800, color: T.white, marginBottom: 6 }}>
          ยินดีด้วย! 🏆
        </div>
        <div style={{ fontSize: 15, color: T.muted2, fontFamily: T.sans, marginBottom: 24 }}>
          คุณได้เปิดใช้งาน{" "}
          <strong style={{ color: pkgData.color, fontWeight: 700 }}>{pkgData.name} Plan</strong>{" "}
          เรียบร้อยแล้ว
        </div>

        {/* Law of Common Region: order box is its own container */}
        <div style={{
          background: T.bg3, borderRadius: 14, padding: "16px 20px", marginBottom: 24,
          border: `1px solid ${T.border}`, boxShadow: "var(--shadow-sm)",
        }}>
          <div style={{ fontSize: 10, color: T.muted, fontFamily: T.mono, letterSpacing: 1.5,
            textTransform: "uppercase", marginBottom: 8 }}>ORDER CONFIRMED</div>
          <div style={{ fontSize: 20, fontFamily: T.mono, fontWeight: 700, color: T.gold,
            letterSpacing: 2, marginBottom: 12 }}>{orderId}</div>
          {/* Proximity: related next-step items grouped */}
          {[
            { icon:"📧", txt: "รับอีเมลยืนยันภายใน 5 นาที" },
            { icon:"⚙",  txt: "เปิดใช้งานภายใน 2–4 ชั่วโมง" },
            { icon:"📞", txt: "สอบถาม: 081-781-7773 (Buff)" },
          ].map(r => (
            <div key={r.txt} style={{ display:"flex", alignItems:"center", gap:10,
              padding:"7px 0", borderTop:`1px solid ${T.border}`,
              fontSize:12, color: T.muted2, fontFamily: T.sans, textAlign:"left" }}>
              <span style={{ fontSize:15, width:20, textAlign:"center" }}>{r.icon}</span>
              {r.txt}
            </div>
          ))}
        </div>

        {/* Doherty: staggered appear of next steps */}
        {step >= 1 && (
          <div style={{ animation: "fadeUp 0.4s ease", marginBottom: 20 }}>
            <div style={{ fontSize: 11, color: T.muted, fontFamily: T.sans, marginBottom: 10 }}>
              สิ่งที่คุณจะได้ทำต่อไป:
            </div>
            <div style={{ display:"flex", gap: 8, justifyContent:"center", flexWrap:"wrap" }}>
              {["✓ ตั้งค่าองค์กร", "✓ สร้าง BIA แรก", "✓ เชิญทีมงาน"].map(s => (
                <span key={s} style={{
                  background: T.goldBg, border: `1px solid ${T.gold}40`,
                  color: T.gold, borderRadius: 20, padding: "4px 12px",
                  fontSize: 11, fontFamily: T.sans, fontWeight: 600,
                }}>{s}</span>
              ))}
            </div>
          </div>
        )}

        {/* Serial Position: CTA last (recency effect) — Fitts: full width */}
        <Btn full size="lg" onClick={onContinue}>เข้าสู่ Dashboard ของคุณ →</Btn>
      </div>
    </div>
  );
}

// ── AppCore: actual app logic (was App) ──────────────────────────────────
export function AppCore({ tenant }) {
  const [view,             setView]           = useState("welcome");
  const [authModal,        setAuthModal]       = useState(null);
  const [payModal,         setPayModal]        = useState(null);
  const [successModal,     setSuccessModal]    = useState(null);
  const [user,             setUser]            = useState(null);
  const [activePkg,        setActivePkg]       = useState("professional");
  const [payBilling,       setPayBilling]      = useState("monthly");
  const [showOnboarding,   setShowOnboarding]  = useState(false);
  const [rtUpgrade,        setRtUpgrade]       = useState(null);   // Realtime plan upgrade

  // ── Tenant-aware: ถ้าเป็น subdomain tenant ให้ skip welcome และไป login
  useEffect(() => {
    if (tenant?.type === "tenant") {
      // Tenant subdomain → แสดง login/dashboard ทันที ไม่ผ่าน welcome
      // (ถ้ายังไม่ได้ login จะแสดง authModal อัตโนมัติ)
    }
  }, [tenant]);

  // ── Helper: load user profile after auth ─────────────────
  const loadProfile = useCallback(async (userId, userEmail) => {
    const { data: profile } = await supa
      .from("profiles")
      .select("full_name, org_id, organizations(name), subscriptions(plan,status)")
      .eq("id", userId)
      .single();
    if (!profile) return null;
    const plan = profile?.subscriptions?.[0]?.plan ?? "free";
    const u = {
      id:    userId,
      name:  profile.full_name ?? userEmail?.split("@")[0] ?? "ผู้ใช้",
      email: userEmail,
      org:   profile.organizations?.name ?? "—",
      plan,
      orgId: profile.org_id,
    };
    return u;
  }, []);

  // ── Restore session on mount + handle OAuth callback ─────
  useEffect(() => {
    (async () => {
      // 1. Check for OAuth redirect (hash contains access_token)
      if (window.location.hash.includes("access_token")) {
        const result = await supa.auth.handleOAuthCallback();
        if (result?.user) {
          // Short delay for DB trigger to create profile
          await new Promise(r => setTimeout(r, 1200));
          const u = await loadProfile(result.user.id, result.user.email);
          if (u) {
            setUser(u); setActivePkg(u.plan !== "free" ? u.plan : "professional");
            setView("dashboard"); setShowOnboarding(true);
          }
          return;
        }
      }

      // 2. Restore existing session
      const { data: { session } } = await supa.auth.getSession();
      if (!session?.user) return;
      const u = await loadProfile(session.user.id, session.user.email);
      if (u) {
        setUser(u); setActivePkg(u.plan !== "free" ? u.plan : "professional");
        setView("dashboard");
      }
    })();
  }, []);

  // ── Realtime: watch payment_orders for live upgrade ───────
  useEffect(() => {
    if (!user?.orgId) return;

    // Channel 1: payment_orders — when status → confirmed
    const orderCh = supa.channel("rt-orders-" + user.orgId)
      .on("postgres_changes", {
        event: "UPDATE", schema: "public", table: "payment_orders",
        filter: `org_id=eq.${user.orgId}`,
      }, async (payload) => {
        const rec = payload.new ?? payload;
        if (rec.status === "confirmed") {
          // Reload subscription to get new plan
          const { data: sub } = await supa
            .from("subscriptions")
            .select("plan")
            .eq("org_id", user.orgId)
            .single();
          if (sub?.plan && sub.plan !== "free") {
            setActivePkg(sub.plan);
            setUser(u => u ? { ...u, plan: sub.plan } : u);
            setRtUpgrade(sub.plan);  // Show live upgrade modal
          }
        }
      })
      .subscribe((status) => {
        if (status === "CHANNEL_ERROR") console.warn("Realtime: orders channel error");
      });

    // Channel 2: subscriptions — plan change (e.g. renewal, downgrade)
    const subCh = supa.channel("rt-subs-" + user.orgId)
      .on("postgres_changes", {
        event: "UPDATE", schema: "public", table: "subscriptions",
        filter: `org_id=eq.${user.orgId}`,
      }, (payload) => {
        const rec = payload.new ?? payload;
        if (rec.plan && rec.plan !== activePkg) {
          setActivePkg(rec.plan);
          setUser(u => u ? { ...u, plan: rec.plan } : u);
        }
      })
      .subscribe();

    return () => {
      supa.removeChannel("rt-orders-" + user.orgId);
      supa.removeChannel("rt-subs-"   + user.orgId);
    };
  }, [user?.orgId]);

  const handleOpenAuth = (mode) => setAuthModal(mode);
  const handleCloseAuth = () => setAuthModal(null);

  const handleSelectPkg = (pkgId, billing) => {
    setActivePkg(pkgId);
    setPayBilling(billing || "monthly");
    if (user) {
      setPayModal({ pkg: pkgId, billing: billing || "monthly" });
    } else {
      setAuthModal("register");
    }
  };

  const handleAuthSuccess = (u) => {
    setUser(u);
    setAuthModal(null);
    setView("dashboard");
    // PLG: trigger onboarding for new users (not login)
    if (authModal === "register") {
      setShowOnboarding(true);
    }
    // If package was pre-selected and paid, open payment modal
    if (activePkg && activePkg !== "free" && authModal === "register") {
      setTimeout(() => setPayModal({ pkg: activePkg, billing: payBilling }), 400);
    }
  };

  const handlePaySuccess = (orderRef) => {
    setPayModal(null);
    setSuccessModal({ pkg: activePkg, orderRef: orderRef ?? null });
  };

  const handleContinueToDash = () => {
    setSuccessModal(null);
    setView("dashboard");
  };

  return (
    <>
      <FontLink />
      {view === "welcome" && (
        <WelcomePageModule
          onOpenAuth={(mode) => {
            if (user) { setView("dashboard"); return; }
            handleOpenAuth(mode);
          }}
          onSelectPkg={handleSelectPkg}
        />
      )}
      {view === "dashboard" && user && (
        <DashboardModule
          user={user}
          pkg={activePkg}
          onLogout={async () => {
            await supa.auth.signOut();
            clearSession();
            setUser(null); setView("welcome"); setShowOnboarding(false);
          }}
          onUpgrade={() => setPayModal({ pkg: "professional", billing: "monthly" })}
          showOnboarding={showOnboarding}
          onOnboardingDone={() => setShowOnboarding(false)}
        />
      )}
      {authModal && (
        <AuthModalModule
          mode={authModal}
          selectedPkg={activePkg}
          onClose={handleCloseAuth}
          onSuccess={handleAuthSuccess}
        />
      )}
      {payModal && user && (
        <PaymentModalModule
          pkg={PACKAGES.find(p => p.id === payModal.pkg)}
          billing={payModal.billing || "monthly"}
          user={user}
          onClose={() => setPayModal(null)}
          onSuccess={handlePaySuccess}
        />
      )}
      {successModal && (
        <SuccessModalModule pkg={successModal?.pkg ?? successModal} onContinue={handleContinueToDash} />
      )}
      {/* ⚡ Realtime Upgrade Modal — Peak-End peak moment */}
      {rtUpgrade && (
        <RealtimeUpgradeModalModule
          newPlan={rtUpgrade}
          onDismiss={() => {
            setRtUpgrade(null);
            setView("dashboard");
          }}
        />
      )}
    </>
  );
}
